"""
Parameterized generator for GH746_echo_2887.

Source PR:    https://github.com/labstack/echo/pull/2887
Source Issue: N/A

Seed varies: renames 'absolute' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH746_echo_2887'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH746_echo_2887'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('absolute', 'absolute' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH746_echo_2887',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'labstack/echo',
                "pr_number": 2887,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/labstack/echo/pull/2887",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'middleware/static.go': '// SPDX-License-Identifier: MIT\n// SPDX-FileCopyrightText: © 2015 LabStack LLC and Echo contributors\n\npackage middleware\n\nimport (\n\t"errors"\n\t"fmt"\n\t"html/template"\n\t"io"\n\t"io/fs"\n\t"net/http"\n\t"net/url"\n\t"os"\n\t"path"\n\t"strconv"\n\t"strings"\n\n\t"github.com/labstack/echo/v5"\n)\n\n// StaticConfig defines the config for Static middleware.\ntype StaticConfig struct {\n\t// Skipper defines a function to skip middleware.\n\tSkipper Skipper\n\n\t// Root directory from where the static content is served (relative to given Filesystem).\n\t// `Root: "."` means root folder from Filesystem.\n\t// Required.\n\tRoot string\n\n\t// Filesystem provides access to the static content.\n\t// Optional. Defaults to echo.Filesystem (serves files from `.` folder where executable is started)\n\tFilesystem fs.FS\n\n\t// Index file for serving a directory.\n\t// Optional. Default value "index.html".\n\tIndex string\n\n\t// Enable HTML5 mode by forwarding all not-found requests to root so that\n\t// SPA (single-page application) can handle the routing.\n\t// Optional. Default value false.\n\tHTML5 bool\n\n\t// Enable directory browsing.\n\t// Optional. Default value false.\n\tBrowse bool\n\n\t// Enable ignoring of the base of the URL path.\n\t// Example: when assigning a static middleware to a non root path group,\n\t// the filesystem path is not doubled\n\t// Optional. Default value false.\n\tIgnoreBase bool\n\n\t// DisablePathUnescaping disables path parameter (param: *) unescaping. This is useful when router is set to unescape\n\t// all parameter and doing it again in this middleware would corrupt filename that is requested.\n\tDisablePathUnescaping bool\n\n\t// DirectoryListTemplate is template to list directory contents\n\t// Optional. Default to `directoryListHTMLTemplate` constant below.\n\tDirectoryListTemplate string\n}\n\nconst directoryListHTMLTemplate = `\n<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8">\n  <meta name="viewport" content="width=device-width, initial-scale=1.0">\n  <meta http-equiv="X-UA-Compatible" content="ie=edge">\n  <title>{{ .Name }}</title>\n  <style>\n    body {\n\t\t\tfont-family: Menlo, Consolas, monospace;\n\t\t\tpadding: 48px;\n\t\t}\n\t\theader {\n\t\t\tpadding: 4px 16px;\n\t\t\tfont-size: 24px;\n\t\t}\n    ul {\n\t\t\tlist-style-type: none;\n\t\t\tmargin: 0;\n    \tpadding: 20px 0 0 0;\n\t\t\tdisplay: flex;\n\t\t\tflex-wrap: wrap;\n    }\n    li {\n\t\t\twidth: 300px;\n\t\t\tpadding: 16px;\n\t\t}\n\t\tli a {\n\t\t\tdisplay: block;\n\t\t\toverflow: hidden;\n\t\t\twhite-space: nowrap;\n\t\t\ttext-overflow: ellipsis;\n\t\t\ttext-decoration: none;\n\t\t\ttransition: opacity 0.25s;\n\t\t}\n\t\tli span {\n\t\t\tcolor: #707070;\n\t\t\tfont-size: 12px;\n\t\t}\n\t\tli a:hover {\n\t\t\topacity: 0.50;\n\t\t}\n\t\t.dir {\n\t\t\tcolor: #E91E63;\n\t\t}\n\t\t.file {\n\t\t\tcolor: #673AB7;\n\t\t}\n  </style>\n</head>\n<body>\n\t<header>\n\t\t{{ .Name }}\n\t</header>\n\t<ul>\n\t\t{{ range .Files }}\n\t\t<li>\n\t\t{{ if .Dir }}\n\t\t\t{{ $name := print .Name "/" }}\n\t\t\t<a class="dir" href="{{ $name }}">{{ $name }}</a>\n\t\t\t{{ else }}\n\t\t\t<a class="file" href="{{ .Name }}">{{ .Name }}</a>\n\t\t\t<span>{{ .Size }}</span>\n\t\t{{ end }}\n\t\t</li>\n\t\t{{ end }}\n  </ul>\n</body>\n</html>\n`\n\n// DefaultStaticConfig is the default Static middleware config.\nvar DefaultStaticConfig = StaticConfig{\n\tSkipper: DefaultSkipper,\n\tIndex:   "index.html",\n}\n\n// Static returns a Static middleware to serves static content from the provided root directory.\nfunc Static(root string) echo.MiddlewareFunc {\n\tc := DefaultStaticConfig\n\tc.Root = root\n\treturn StaticWithConfig(c)\n}\n\n// StaticWithConfig returns a Static middleware to serves static content or panics on invalid configuration.\nfunc StaticWithConfig(config StaticConfig) echo.MiddlewareFunc {\n\treturn toMiddlewareOrPanic(config)\n}\n\n// ToMiddleware converts StaticConfig to middleware or returns an error for invalid configuration\nfunc (config StaticConfig) ToMiddleware() (echo.MiddlewareFunc, error) {\n\t// Defaults\n\tif config.Root == "" {\n\t\tconfig.Root = "." // For security we want to restrict to CWD.\n\t}\n\tif config.Skipper == nil {\n\t\tconfig.Skipper = DefaultStaticConfig.Skipper\n\t}\n\tif config.Index == "" {\n\t\tconfig.Index = DefaultStaticConfig.Index\n\t}\n\tif config.DirectoryListTemplate == "" {\n\t\tconfig.DirectoryListTemplate = directoryListHTMLTemplate\n\t}\n\n\tdirListTemplate, tErr := template.New("index").Parse(config.DirectoryListTemplate)\n\tif tErr != nil {\n\t\treturn nil, fmt.Errorf("echo static middleware directory list template parsing error: %w", tErr)\n\t}\n\n\treturn func(next echo.HandlerFunc) echo.HandlerFunc {\n\t\treturn func(c *echo.Context) (err error) {\n\t\t\tif config.Skipper(c) {\n\t\t\t\treturn next(c)\n\t\t\t}\n\n\t\t\tp := c.Request().URL.Path\n\t\t\tpathUnescape := true\n\t\t\tif strings.HasSuffix(c.Path(), "*") { // When serving from a group, e.g. `/static*`.\n\t\t\t\tp = c.Param("*")\n\t\t\t\tpathUnescape = !config.DisablePathUnescaping // because router could already do PathUnescape\n\t\t\t}\n\t\t\tif pathUnescape {\n\t\t\t\tp, err = url.PathUnescape(p)\n\t\t\t\tif err != nil {\n\t\t\t\t\treturn err\n\t\t\t\t}\n\t\t\t}\n\t\t\t// Security: We use path.Clean() (not filepath.Clean()) because:\n\t\t\t// 1. HTTP URLs always use forward slashes, regardless of server OS\n\t\t\t// 2. path.Clean() provides platform-independent behavior for URL paths\n\t\t\t// 3. The "/" prefix forces absolute path interpretation, removing ".." components\n\t\t\t// 4. Backslashes are treated as literal characters (not path separators), preventing traversal\n\t\t\t// See static_windows.go for Go 1.20+ filepath.Clean compatibility notes\n\t\t\tname := path.Join(config.Root, path.Clean("/"+p)) // "/"+ for security\n\n\t\t\tif config.IgnoreBase {\n\t\t\t\troutePath := path.Base(strings.TrimRight(c.Path(), "/*"))\n\t\t\t\tbaseURLPath := path.Base(p)\n\t\t\t\tif baseURLPath == routePath {\n\t\t\t\t\ti := strings.LastIndex(name, routePath)\n\t\t\t\t\tname = name[:i] + strings.Replace(name[i:], routePath, "", 1)\n\t\t\t\t}\n\t\t\t}\n\n\t\t\tcurrentFS := config.Filesystem\n\t\t\tif currentFS == nil {\n\t\t\t\tcurrentFS = c.Echo().Filesystem\n\t\t\t}\n\n\t\t\tfile, err := currentFS.Open(name)\n\t\t\tif err != nil {\n\t\t\t\tif !isIgnorableOpenFileError(err) {\n\t\t\t\t\treturn err\n\t\t\t\t}\n\t\t\t\t// file with that path did not exist, so we continue down in middleware/handler chain, hoping that we end up in\n\t\t\t\t// handler that is meant to handle this request\n\t\t\t\terr = next(c)\n\t\t\t\tif err == nil {\n\t\t\t\t\treturn nil\n\t\t\t\t}\n\n\t\t\t\tvar he echo.HTTPStatusCoder\n\t\t\t\tif !(errors.As(err, &he) && config.HTML5 && he.StatusCode() == http.StatusNotFound) {\n\t\t\t\t\treturn err\n\t\t\t\t}\n\t\t\t\t// is case HTML5 mode is enabled + echo 404 we serve index to the client\n\t\t\t\tfile, err = currentFS.Open(path.Join(config.Root, config.Index))\n\t\t\t\tif err != nil {\n\t\t\t\t\treturn err\n\t\t\t\t}\n\t\t\t}\n\n\t\t\tdefer file.Close()\n\n\t\t\tinfo, err := file.Stat()\n\t\t\tif err != nil {\n\t\t\t\treturn err\n\t\t\t}\n\n\t\t\tif info.IsDir() {\n\t\t\t\tindex, err := currentFS.Open(path.Join(name, config.Index))\n\t\t\t\tif err != nil {\n\t\t\t\t\tif config.Browse {\n\t\t\t\t\t\treturn listDir(dirListTemplate, name, currentFS, c.Response())\n\t\t\t\t\t}\n\n\t\t\t\t\treturn next(c)\n\t\t\t\t}\n\n\t\t\t\tdefer index.Close()\n\n\t\t\t\tinfo, err = index.Stat()\n\t\t\t\tif err != nil {\n\t\t\t\t\treturn err\n\t\t\t\t}\n\n\t\t\t\treturn serveFile(c, index, info)\n\t\t\t}\n\n\t\t\treturn serveFile(c, file, info)\n\t\t}\n\t}, nil\n}\n\nfunc serveFile(c *echo.Context, file fs.File, info os.FileInfo) error {\n\tff, ok := file.(io.ReadSeeker)\n\tif !ok {\n\t\treturn errors.New("file does not implement io.ReadSeeker")\n\t}\n\thttp.ServeContent(c.Response(), c.Request(), info.Name(), info.ModTime(), ff)\n\treturn nil\n}\n\nfunc listDir(t *template.Template, name string, filesystem fs.FS, res http.ResponseWriter) error {\n\t// Create directory index\n\tres.Header().Set(echo.HeaderContentType, echo.MIMETextHTMLCharsetUTF8)\n\tdata := struct {\n\t\tName  string\n\t\tFiles []any\n\t}{\n\t\tName: name,\n\t}\n\terr := fs.WalkDir(filesystem, ".", func(path string, d fs.DirEntry, err error) error {\n\t\tif err != nil {\n\t\t\treturn err\n\t\t}\n\n\t\tinfo, infoErr := d.Info()\n\t\tif infoErr != nil {\n\t\t\treturn fmt.Errorf("static middleware list dir error when getting file info: %w", infoErr)\n\t\t}\n\t\tdata.Files = append(data.Files, struct {\n\t\t\tName string\n\t\t\tDir  bool\n\t\t\tSize string\n\t\t}{d.Name(), d.IsDir(), format(info.Size())})\n\n\t\treturn nil\n\t})\n\tif err != nil {\n\t\treturn err\n\t}\n\n\treturn t.Execute(res, data)\n}\n\n// format formats bytes integer to human readable string.\n// For example, 31323 bytes will return 30.59KB.\nfunc format(b int64) string {\n\tmultiple := ""\n\tvalue := float64(b)\n\n\tswitch {\n\tcase b >= EB:\n\t\tvalue /= float64(EB)\n\t\tmultiple = "EB"\n\tcase b >= PB:\n\t\tvalue /= float64(PB)\n\t\tmultiple = "PB"\n\tcase b >= TB:\n\t\tvalue /= float64(TB)\n\t\tmultiple = "TB"\n\tcase b >= GB:\n\t\tvalue /= float64(GB)\n\t\tmultiple = "GB"\n\tcase b >= MB:\n\t\tvalue /= float64(MB)\n\t\tmultiple = "MB"\n\tcase b >= KB:\n\t\tvalue /= float64(KB)\n\t\tmultiple = "KB"\n\tcase b == 0:\n\t\treturn "0"\n\tdefault:\n\t\treturn strconv.FormatInt(b, 10) + "B"\n\t}\n\n\treturn fmt.Sprintf("%.2f%s", value, multiple)\n}\n',
            'middleware/static_test.go': '// SPDX-License-Identifier: MIT\n// SPDX-FileCopyrightText: © 2015 LabStack LLC and Echo contributors\n\npackage middleware\n\nimport (\n\t"io/fs"\n\t"net/http"\n\t"net/http/httptest"\n\t"os"\n\t"strings"\n\t"testing"\n\t"testing/fstest"\n\n\t"github.com/labstack/echo/v5"\n\t"github.com/stretchr/testify/assert"\n)\n\nfunc TestStatic_useCaseForApiAndSPAs(t *testing.T) {\n\te := echo.New()\n\n\t// serve single page application (SPA) files from server root\n\te.Use(StaticWithConfig(StaticConfig{\n\t\tRoot: ".",\n\t\t// by default Echo filesystem is fixed to `./` but this does not allow `../` (moving up in folder structure past filesystem root)\n\t\tFilesystem: os.DirFS("../_fixture"),\n\t}))\n\n\t// all requests to `/api/*` will end up in echo handlers (assuming there is not `api` folder and files)\n\tapi := e.Group("/api")\n\tusers := api.Group("/users")\n\tusers.GET("/info", func(c *echo.Context) error {\n\t\treturn c.String(http.StatusOK, "users info")\n\t})\n\n\treq := httptest.NewRequest(http.MethodGet, "/api/users/info", nil)\n\trec := httptest.NewRecorder()\n\te.ServeHTTP(rec, req)\n\tassert.Equal(t, http.StatusOK, rec.Code)\n\tassert.Equal(t, "users info", rec.Body.String())\n\n\treq = httptest.NewRequest(http.MethodGet, "/index.html", nil)\n\trec = httptest.NewRecorder()\n\te.ServeHTTP(rec, req)\n\tassert.Equal(t, http.StatusOK, rec.Code)\n\tassert.Contains(t, rec.Body.String(), "<title>Echo</title>")\n\n}\n\nfunc TestStatic(t *testing.T) {\n\tvar testCases = []struct {\n\t\tname                 string\n\t\tgivenConfig          *StaticConfig\n\t\tgivenAttachedToGroup string\n\t\twhenURL              string\n\t\texpectContains       string\n\t\texpectLength         string\n\t\texpectCode           int\n\t}{\n\t\t{\n\t\t\tname:           "ok, serve index with Echo message",\n\t\t\twhenURL:        "/",\n\t\t\texpectCode:     http.StatusOK,\n\t\t\texpectContains: "<title>Echo</title>",\n\t\t},\n\t\t{\n\t\t\tname:         "ok, serve file from subdirectory",\n\t\t\twhenURL:      "/images/walle.png",\n\t\t\texpectCode:   http.StatusOK,\n\t\t\texpectLength: "219885",\n\t\t},\n\t\t{\n\t\t\tname: "ok, when html5 mode serve index for any static file that does not exist",\n\t\t\tgivenConfig: &StaticConfig{\n\t\t\t\tRoot:  "_fixture",\n\t\t\t\tHTML5: true,\n\t\t\t},\n\t\t\twhenURL:        "/random",\n\t\t\texpectCode:     http.StatusOK,\n\t\t\texpectContains: "<title>Echo</title>",\n\t\t},\n\t\t{\n\t\t\tname: "ok, serve index as directory index listing files directory",\n\t\t\tgivenConfig: &StaticConfig{\n\t\t\t\tRoot:   "_fixture/certs",\n\t\t\t\tBrowse: true,\n\t\t\t},\n\t\t\twhenURL:        "/",\n\t\t\texpectCode:     http.StatusOK,\n\t\t\texpectContains: "cert.pem",\n\t\t},\n\t\t{\n\t\t\tname: "ok, serve directory index with IgnoreBase and browse",\n\t\t\tgivenConfig: &StaticConfig{\n\t\t\t\tRoot:       "_fixture/_fixture/", // <-- last `_fixture/` is overlapping with group path and needs to be ignored\n\t\t\t\tIgnoreBase: true,\n\t\t\t\tBrowse:     true,\n\t\t\t},\n\t\t\tgivenAttachedToGroup: "/_fixture",\n\t\t\twhenURL:              "/_fixture/",\n\t\t\texpectCode:           http.StatusOK,\n\t\t\texpectContains:       `<a class="file" href="README.md">README.md</a>`,\n\t\t},\n\t\t{\n\t\t\tname: "ok, serve file with IgnoreBase",\n\t\t\tgivenConfig: &StaticConfig{\n\t\t\t\tRoot:       "_fixture/_fixture/", // <-- last `_fixture/` is overlapping with group path and needs to be ignored\n\t\t\t\tIgnoreBase: true,\n\t\t\t\tBrowse:     true,\n\t\t\t},\n\t\t\tgivenAttachedToGroup: "/_fixture",\n\t\t\twhenURL:              "/_fixture/README.md",\n\t\t\texpectCode:           http.StatusOK,\n\t\t\texpectContains:       "This directory is used for the static middleware test",\n\t\t},\n\t\t{\n\t\t\tname:           "nok, file not found",\n\t\t\twhenURL:        "/none",\n\t\t\texpectCode:     http.StatusNotFound,\n\t\t\texpectContains: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "nok, do not allow directory traversal (backslash - windows separator)",\n\t\t\twhenURL:        `/..\\\\middleware/basic_auth.go`,\n\t\t\texpectCode:     http.StatusNotFound,\n\t\t\texpectContains: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "nok,do not allow directory traversal (slash - unix separator)",\n\t\t\twhenURL:        `/../middleware/basic_auth.go`,\n\t\t\texpectCode:     http.StatusNotFound,\n\t\t\texpectContains: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "ok, when no file then a handler will care of the request",\n\t\t\twhenURL:        "/regular-handler",\n\t\t\texpectCode:     http.StatusOK,\n\t\t\texpectContains: "ok",\n\t\t},\n\t\t{\n\t\t\tname: "ok, skip middleware and serve handler",\n\t\t\tgivenConfig: &StaticConfig{\n\t\t\t\tRoot: "_fixture/images/",\n\t\t\t\tSkipper: func(c *echo.Context) bool {\n\t\t\t\t\treturn true\n\t\t\t\t},\n\t\t\t},\n\t\t\twhenURL:        "/walle.png",\n\t\t\texpectCode:     http.StatusTeapot,\n\t\t\texpectContains: "walle",\n\t\t},\n\t\t{\n\t\t\tname: "nok, when html5 fail if the index file does not exist",\n\t\t\tgivenConfig: &StaticConfig{\n\t\t\t\tRoot:  "_fixture",\n\t\t\t\tHTML5: true,\n\t\t\t\tIndex: "missing.html",\n\t\t\t},\n\t\t\twhenURL:    "/random",\n\t\t\texpectCode: http.StatusInternalServerError,\n\t\t},\n\t\t{\n\t\t\tname: "ok, serve from http.FileSystem",\n\t\t\tgivenConfig: &StaticConfig{\n\t\t\t\tRoot:       "_fixture",\n\t\t\t\tFilesystem: os.DirFS(".."),\n\t\t\t},\n\t\t\twhenURL:        "/",\n\t\t\texpectCode:     http.StatusOK,\n\t\t\texpectContains: "<title>Echo</title>",\n\t\t},\n\t\t{\n\t\t\tname:           "nok, URL encoded path traversal (single encoding)",\n\t\t\twhenURL:        "/%2e%2e%2fmiddleware/basic_auth.go",\n\t\t\texpectCode:     http.StatusNotFound,\n\t\t\texpectContains: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "nok, URL encoded path traversal (double encoding)",\n\t\t\twhenURL:        "/%252e%252e%252fmiddleware/basic_auth.go",\n\t\t\texpectCode:     http.StatusNotFound,\n\t\t\texpectContains: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "nok, URL encoded path traversal (mixed encoding)",\n\t\t\twhenURL:        "/%2e%2e/middleware/basic_auth.go",\n\t\t\texpectCode:     http.StatusNotFound,\n\t\t\texpectContains: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "nok, backslash URL encoded",\n\t\t\twhenURL:        "/..%5c..%5cmiddleware/basic_auth.go",\n\t\t\texpectCode:     http.StatusNotFound,\n\t\t\texpectContains: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t\t//{ // Under windows, %00 gets cleaned out by `http.ReadRequest` making this test to fail with different code\n\t\t//\tname:           "nok, null byte injection",\n\t\t//\twhenURL:        "/index.html%00.jpg",\n\t\t//\texpectCode:     http.StatusInternalServerError,\n\t\t//\texpectContains: "{\\"message\\":\\"Internal Server Error\\"}\\n",\n\t\t//},\n\t\t{\n\t\t\tname:           "nok, mixed backslash and forward slash traversal",\n\t\t\twhenURL:        "/..\\\\../middleware/basic_auth.go",\n\t\t\texpectCode:     http.StatusNotFound,\n\t\t\texpectContains: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t\t{\n\t\t\tname:           "nok, trailing dots (Windows edge case)",\n\t\t\twhenURL:        "/../middleware/basic_auth.go...",\n\t\t\texpectCode:     http.StatusNotFound,\n\t\t\texpectContains: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t}\n\n\tfor _, tc := range testCases {\n\t\tt.Run(tc.name, func(t *testing.T) {\n\t\t\te := echo.New()\n\t\t\te.Filesystem = os.DirFS("../")\n\n\t\t\tconfig := StaticConfig{Root: "_fixture"}\n\t\t\tif tc.givenConfig != nil {\n\t\t\t\tconfig = *tc.givenConfig\n\t\t\t}\n\t\t\tmiddlewareFunc := StaticWithConfig(config)\n\t\t\tif tc.givenAttachedToGroup != "" {\n\t\t\t\t// middleware is attached to group\n\t\t\t\tsubGroup := e.Group(tc.givenAttachedToGroup, middlewareFunc)\n\t\t\t\t// group without http handlers (routes) does not do anything.\n\t\t\t\t// Request is matched against http handlers (routes) that have group middleware attached to them\n\t\t\t\tsubGroup.GET("", func(c *echo.Context) error { return echo.ErrNotFound })\n\t\t\t\tsubGroup.GET("/*", func(c *echo.Context) error { return echo.ErrNotFound })\n\t\t\t} else {\n\t\t\t\t// middleware is on root level\n\t\t\t\te.Use(middlewareFunc)\n\t\t\t\te.GET("/regular-handler", func(c *echo.Context) error {\n\t\t\t\t\treturn c.String(http.StatusOK, "ok")\n\t\t\t\t})\n\t\t\t\te.GET("/walle.png", func(c *echo.Context) error {\n\t\t\t\t\treturn c.String(http.StatusTeapot, "walle")\n\t\t\t\t})\n\t\t\t}\n\n\t\t\treq := httptest.NewRequest(http.MethodGet, tc.whenURL, nil)\n\t\t\trec := httptest.NewRecorder()\n\n\t\t\te.ServeHTTP(rec, req)\n\n\t\t\tassert.Equal(t, tc.expectCode, rec.Code)\n\t\t\tif tc.expectContains != "" {\n\t\t\t\tresponseBody := rec.Body.String()\n\t\t\t\tassert.Contains(t, responseBody, tc.expectContains)\n\t\t\t}\n\t\t\tif tc.expectLength != "" {\n\t\t\t\tassert.Equal(t, rec.Header().Get(echo.HeaderContentLength), tc.expectLength)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestStatic_GroupWithStatic(t *testing.T) {\n\tvar testCases = []struct {\n\t\tname                 string\n\t\tgivenGroup           string\n\t\tgivenPrefix          string\n\t\tgivenRoot            string\n\t\twhenURL              string\n\t\texpectStatus         int\n\t\texpectHeaderLocation string\n\t\texpectBodyStartsWith string\n\t}{\n\t\t{\n\t\t\tname:                 "ok",\n\t\t\tgivenPrefix:          "/images",\n\t\t\tgivenRoot:            "_fixture/images",\n\t\t\twhenURL:              "/group/images/walle.png",\n\t\t\texpectStatus:         http.StatusOK,\n\t\t\texpectBodyStartsWith: string([]byte{0x89, 0x50, 0x4e, 0x47}),\n\t\t},\n\t\t{\n\t\t\tname:                 "No file",\n\t\t\tgivenPrefix:          "/images",\n\t\t\tgivenRoot:            "_fixture/scripts",\n\t\t\twhenURL:              "/group/images/bolt.png",\n\t\t\texpectStatus:         http.StatusNotFound,\n\t\t\texpectBodyStartsWith: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t\t{\n\t\t\tname:                 "Directory not found (no trailing slash)",\n\t\t\tgivenPrefix:          "/images",\n\t\t\tgivenRoot:            "_fixture/images",\n\t\t\twhenURL:              "/group/images/",\n\t\t\texpectStatus:         http.StatusNotFound,\n\t\t\texpectBodyStartsWith: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t\t{\n\t\t\tname:                 "Directory redirect",\n\t\t\tgivenPrefix:          "/",\n\t\t\tgivenRoot:            "_fixture",\n\t\t\twhenURL:              "/group/folder",\n\t\t\texpectStatus:         http.StatusMovedPermanently,\n\t\t\texpectHeaderLocation: "/group/folder/",\n\t\t\texpectBodyStartsWith: "",\n\t\t},\n\t\t{\n\t\t\tname:                 "Directory redirect",\n\t\t\tgivenPrefix:          "/",\n\t\t\tgivenRoot:            "_fixture",\n\t\t\twhenURL:              "/group/folder%2f..",\n\t\t\texpectStatus:         http.StatusMovedPermanently,\n\t\t\texpectHeaderLocation: "/group/folder/../",\n\t\t\texpectBodyStartsWith: "",\n\t\t},\n\t\t{\n\t\t\tname:                 "Prefixed directory 404 (request URL without slash)",\n\t\t\tgivenGroup:           "_fixture",\n\t\t\tgivenPrefix:          "/folder/", // trailing slash will intentionally not match "/folder"\n\t\t\tgivenRoot:            "_fixture",\n\t\t\twhenURL:              "/_fixture/folder", // no trailing slash\n\t\t\texpectStatus:         http.StatusNotFound,\n\t\t\texpectBodyStartsWith: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t\t{\n\t\t\tname:                 "Prefixed directory redirect (without slash redirect to slash)",\n\t\t\tgivenGroup:           "_fixture",\n\t\t\tgivenPrefix:          "/folder", // no trailing slash shall match /folder and /folder/*\n\t\t\tgivenRoot:            "_fixture",\n\t\t\twhenURL:              "/_fixture/folder", // no trailing slash\n\t\t\texpectStatus:         http.StatusMovedPermanently,\n\t\t\texpectHeaderLocation: "/_fixture/folder/",\n\t\t\texpectBodyStartsWith: "",\n\t\t},\n\t\t{\n\t\t\tname:                 "Directory with index.html",\n\t\t\tgivenPrefix:          "/",\n\t\t\tgivenRoot:            "_fixture",\n\t\t\twhenURL:              "/group/",\n\t\t\texpectStatus:         http.StatusOK,\n\t\t\texpectBodyStartsWith: "<!doctype html>",\n\t\t},\n\t\t{\n\t\t\tname:                 "Prefixed directory with index.html (prefix ending with slash)",\n\t\t\tgivenPrefix:          "/assets/",\n\t\t\tgivenRoot:            "_fixture",\n\t\t\twhenURL:              "/group/assets/",\n\t\t\texpectStatus:         http.StatusOK,\n\t\t\texpectBodyStartsWith: "<!doctype html>",\n\t\t},\n\t\t{\n\t\t\tname:                 "Prefixed directory with index.html (prefix ending without slash)",\n\t\t\tgivenPrefix:          "/assets",\n\t\t\tgivenRoot:            "_fixture",\n\t\t\twhenURL:              "/group/assets/",\n\t\t\texpectStatus:         http.StatusOK,\n\t\t\texpectBodyStartsWith: "<!doctype html>",\n\t\t},\n\t\t{\n\t\t\tname:                 "Sub-directory with index.html",\n\t\t\tgivenPrefix:          "/",\n\t\t\tgivenRoot:            "_fixture",\n\t\t\twhenURL:              "/group/folder/",\n\t\t\texpectStatus:         http.StatusOK,\n\t\t\texpectBodyStartsWith: "<!doctype html>",\n\t\t},\n\t\t{\n\t\t\tname:                 "do not allow directory traversal (backslash - windows separator)",\n\t\t\tgivenPrefix:          "/",\n\t\t\tgivenRoot:            "_fixture/",\n\t\t\twhenURL:              `/group/..\\\\middleware/basic_auth.go`,\n\t\t\texpectStatus:         http.StatusNotFound,\n\t\t\texpectBodyStartsWith: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t\t{\n\t\t\tname:                 "do not allow directory traversal (slash - unix separator)",\n\t\t\tgivenPrefix:          "/",\n\t\t\tgivenRoot:            "_fixture/",\n\t\t\twhenURL:              `/group/../middleware/basic_auth.go`,\n\t\t\texpectStatus:         http.StatusNotFound,\n\t\t\texpectBodyStartsWith: "{\\"message\\":\\"Not Found\\"}\\n",\n\t\t},\n\t}\n\n\tfor _, tc := range testCases {\n\t\tt.Run(tc.name, func(t *testing.T) {\n\t\t\te := echo.New()\n\t\t\te.Filesystem = os.DirFS("../") // so we can access test files\n\n\t\t\tgroup := "/group"\n\t\t\tif tc.givenGroup != "" {\n\t\t\t\tgroup = tc.givenGroup\n\t\t\t}\n\t\t\tg := e.Group(group)\n\t\t\tg.Static(tc.givenPrefix, tc.givenRoot)\n\n\t\t\treq := httptest.NewRequest(http.MethodGet, tc.whenURL, nil)\n\t\t\trec := httptest.NewRecorder()\n\n\t\t\te.ServeHTTP(rec, req)\n\n\t\t\tassert.Equal(t, tc.expectStatus, rec.Code)\n\t\t\tbody := rec.Body.String()\n\t\t\tif tc.expectBodyStartsWith != "" {\n\t\t\t\tassert.True(t, strings.HasPrefix(body, tc.expectBodyStartsWith))\n\t\t\t} else {\n\t\t\t\tassert.Equal(t, "", body)\n\t\t\t}\n\n\t\t\tif tc.expectHeaderLocation != "" {\n\t\t\t\tassert.Equal(t, tc.expectHeaderLocation, rec.Header().Get(echo.HeaderLocation))\n\t\t\t} else {\n\t\t\t\t_, ok := rec.Result().Header[echo.HeaderLocation]\n\t\t\t\tassert.False(t, ok)\n\t\t\t}\n\t\t})\n\t}\n}\n\nfunc TestMustStaticWithConfig_panicsInvalidDirListTemplate(t *testing.T) {\n\tassert.Panics(t, func() {\n\t\tStaticWithConfig(StaticConfig{DirectoryListTemplate: `{{}`})\n\t})\n}\n\nfunc TestFormat(t *testing.T) {\n\tvar testCases = []struct {\n\t\tname   string\n\t\twhen   int64\n\t\texpect string\n\t}{\n\t\t{\n\t\t\tname:   "byte",\n\t\t\twhen:   0,\n\t\t\texpect: "0",\n\t\t},\n\t\t{\n\t\t\tname:   "bytes",\n\t\t\twhen:   515,\n\t\t\texpect: "515B",\n\t\t},\n\t\t{\n\t\t\tname:   "KB",\n\t\t\twhen:   31323,\n\t\t\texpect: "30.59KB",\n\t\t},\n\t\t{\n\t\t\tname:   "MB",\n\t\t\twhen:   13231323,\n\t\t\texpect: "12.62MB",\n\t\t},\n\t\t{\n\t\t\tname:   "GB",\n\t\t\twhen:   7323232398,\n\t\t\texpect: "6.82GB",\n\t\t},\n\t\t{\n\t\t\tname:   "TB",\n\t\t\twhen:   1_099_511_627_776,\n\t\t\texpect: "1.00TB",\n\t\t},\n\t\t{\n\t\t\tname:   "PB",\n\t\t\twhen:   9923232398434432,\n\t\t\texpect: "8.81PB",\n\t\t},\n\t\t{\n\t\t\t// test with 7EB because of https://github.com/labstack/gommon/pull/38 and https://github.com/labstack/gommon/pull/43\n\t\t\t//\n\t\t\t// 8 exbi equals 2^64, therefore it cannot be stored in int64. The tests use\n\t\t\t// the fact that on x86_64 the following expressions holds true:\n\t\t\t// int64(0) - 1 == math.MaxInt64.\n\t\t\t//\n\t\t\t// However, this is not true for other platforms, specifically aarch64, s390x\n\t\t\t// and ppc64le.\n\t\t\tname:   "EB",\n\t\t\twhen:   8070450532247929000,\n\t\t\texpect: "7.00EB",\n\t\t},\n\t}\n\n\tfor _, tc := range testCases {\n\t\tt.Run(tc.name, func(t *testing.T) {\n\t\t\tresult := format(tc.when)\n\t\t\tassert.Equal(t, tc.expect, result)\n\t\t})\n\t}\n}\n\nfunc TestStatic_CustomFS(t *testing.T) {\n\tvar testCases = []struct {\n\t\tname           string\n\t\tfilesystem     fs.FS\n\t\troot           string\n\t\twhenURL        string\n\t\texpectContains string\n\t\texpectCode     int\n\t}{\n\t\t{\n\t\t\tname:           "ok, serve index with Echo message",\n\t\t\twhenURL:        "/",\n\t\t\tfilesystem:     os.DirFS("../_fixture"),\n\t\t\texpectCode:     http.StatusOK,\n\t\t\texpectContains: "<title>Echo</title>",\n\t\t},\n\n\t\t{\n\t\t\tname:           "ok, serve index with Echo message",\n\t\t\twhenURL:        "/_fixture/",\n\t\t\tfilesystem:     os.DirFS(".."),\n\t\t\texpectCode:     http.StatusOK,\n\t\t\texpectContains: "<title>Echo</title>",\n\t\t},\n\t\t{\n\t\t\tname:    "ok, serve file from map fs",\n\t\t\twhenURL: "/file.txt",\n\t\t\tfilesystem: fstest.MapFS{\n\t\t\t\t"file.txt": &fstest.MapFile{Data: []byte("file.txt is ok")},\n\t\t\t},\n\t\t\texpectCode:     http.StatusOK,\n\t\t\texpectContains: "file.txt is ok",\n\t\t},\n\t\t{\n\t\t\tname:       "nok, missing file in map fs",\n\t\t\twhenURL:    "/file.txt",\n\t\t\texpectCode: http.StatusNotFound,\n\t\t\tfilesystem: fstest.MapFS{\n\t\t\t\t"file2.txt": &fstest.MapFile{Data: []byte("file2.txt is ok")},\n\t\t\t},\n\t\t},\n\t\t{\n\t\t\tname:    "nok, file is not a subpath of root",\n\t\t\twhenURL: `/../../secret.txt`,\n\t\t\troot:    "/nested/folder",\n\t\t\tfilesystem: fstest.MapFS{\n\t\t\t\t"secret.txt": &fstest.MapFile{Data: []byte("this is a secret")},\n\t\t\t},\n\t\t\texpectCode: http.StatusNotFound,\n\t\t},\n\t\t{\n\t\t\tname:       "nok, backslash is forbidden",\n\t\t\twhenURL:    `/..\\..\\secret.txt`,\n\t\t\texpectCode: http.StatusNotFound,\n\t\t\troot:       "/nested/folder",\n\t\t\tfilesystem: fstest.MapFS{\n\t\t\t\t"secret.txt": &fstest.MapFile{Data: []byte("this is a secret")},\n\t\t\t},\n\t\t},\n\t}\n\n\tfor _, tc := range testCases {\n\t\tt.Run(tc.name, func(t *testing.T) {\n\t\t\te := echo.New()\n\n\t\t\tconfig := StaticConfig{\n\t\t\t\tRoot:       ".",\n\t\t\t\tFilesystem: tc.filesystem,\n\t\t\t}\n\n\t\t\tif tc.root != "" {\n\t\t\t\tconfig.Root = tc.root\n\t\t\t}\n\n\t\t\tmiddlewareFunc, err := config.ToMiddleware()\n\t\t\tassert.NoError(t, err)\n\n\t\t\te.Use(middlewareFunc)\n\n\t\t\treq := httptest.NewRequest(http.MethodGet, tc.whenURL, nil)\n\t\t\trec := httptest.NewRecorder()\n\n\t\t\te.ServeHTTP(rec, req)\n\n\t\t\tassert.Equal(t, tc.expectCode, rec.Code)\n\t\t\tif tc.expectContains != "" {\n\t\t\t\tresponseBody := rec.Body.String()\n\t\t\t\tassert.Contains(t, responseBody, tc.expectContains)\n\t\t\t}\n\t\t})\n\t}\n}\n',
        }
